const item = $input.item;
const j = item.json;

// ======================================================
// DADOS DE IDENTIFICAÇÃO
// ======================================================

const msg = j.messages?.[0] ?? {};

j.PhoneConnected =
  j.PhoneConnected ??
  j.metadata?.phone_number_id ??
  null;

j.display_phone_number =
  j.display_phone_number ??
  j.metadata?.display_phone_number ??
  null;

j.Phone =
  j.Phone ??
  j.phone ??
  j.contacts?.[0]?.wa_id ??
  msg.from ??
  null;

j.Nome =
  j.Nome ??
  j.contacts?.[0]?.profile?.name ??
  null;

// ======================================================
// CONFIGURAÇÃO POR NÚMERO
// ======================================================

const phonesConfig = {
  1068535889684555: {
    acessToken: "3EA6B3979B12E1B6EDC772620DC9C8F4",
    businessAccountID: "1512857447000297",
    rotaAutenticacao:
      "https://tdev3-ag.icommercial002.inovamobil.com.br/api/chatbot",
    rotaDebitos:
      "https://tdev3-fat.icommercial002.inovamobil.com.br/api/debitos",
  },
};

// ======================================================
// VALIDAÇÃO
// ======================================================

const phoneConnected = (j.PhoneConnected ?? "")
  .toString()
  .replace(/\D+/g, "");

const selected = phonesConfig[phoneConnected];

if (!selected) {
  throw new Error(
    `PhoneConnected (${phoneConnected || "vazio"}) não mapeado em phonesConfig`,
  );
}

// ======================================================
// API
// ======================================================

j.api = {
  AcessToken: selected.acessToken,
  BusinessAccountID: selected.businessAccountID,
  rotaPrincipalDados: selected.rotaPrincipalDados,

  endpoints: {
    ultimasFaturas: `${selected.rotaAutenticacao}/faturas-abertas`,
    retornarUsuario: `${selected.rotaAutenticacao}/retornar-usuario`,
    gerarFatura: `${selected.rotaAutenticacao}/fatura-pdf`,
    retornardebitos: `${selected.rotaDebitos}/listar-debitos-em-abertos`,
  },
};

// ======================================================
// Configurações
// ======================================================

j.negociacao = {
  parcelaMinima: 15,
  parcelasMaximasPorFaixa: [
    {
      ate: 1000,
      maxParcelas: 24
    },
    {
      ate: 2000,
      maxParcelas: 30
    },
    {
      ate: 5000,
      maxParcelas: 40
    },
    {
      ate: 100000,
      maxParcelas: 60
    }
  ]
};


return item;

const j = $input.item.json || {};

const stopBot =
  !!j.statuses?.length ||
  !j.messages?.length;

return [{
  json: {
    ...j,
    stopBot
  }
}];

const item = $input.item;
const j = item.json;

const msg = j.messages?.[0] ?? {};
const interactive = msg.interactive ?? {};

// ======================================================
// DADOS BÁSICOS DA MENSAGEM
// ======================================================

j.message_id = msg.id ?? null;
j.timestamp = msg.timestamp ?? null;
j.message_type = msg.type ?? null;

// ======================================================
// TEXTO
// ======================================================

j.texto = msg.text?.body ?? null;

// ======================================================
// BOTÃO
// ======================================================

j.buttonReply = interactive.button_reply ?? null;

// ======================================================
// LISTA
// ======================================================

j.listReply = interactive.list_reply ?? null;

// ======================================================
// FLAGS
// ======================================================

j.veio_texto = !!j.texto;
j.veio_botao = !!j.buttonReply;
j.veio_lista = !!j.listReply;
j.veio_interactive = j.veio_botao || j.veio_lista;

// ======================================================
// RESPOSTA PADRONIZADA
// ======================================================

j.resposta_id =
  j.buttonReply?.id ??
  j.listReply?.id ??
  null;

j.resposta_titulo =
  j.buttonReply?.title ??
  j.listReply?.title ??
  null;

j.resposta_descricao =
  j.listReply?.description ??
  null;

j.resposta_cliente =
  j.resposta_titulo ??
  j.texto ??
  null;

// ======================================================
// NORMALIZAÇÃO
// ======================================================

j.resposta_normalizada = (j.resposta_id ?? "")
  .toString()
  .trim()
  .toUpperCase()
  .normalize("NFD")
  .replace(/[\u0300-\u036f]/g, "");

// ======================================================
// QUEBRA DO PADRÃO
// BOTAO_01_VER_PENDENCIAS
// LISTA_03_SEM_CONDICOES
// ======================================================

const partes = j.resposta_normalizada.split("_");

j.tipo_resposta = partes[0] ?? null;       // BOTAO | LISTA
j.numero_fluxo = partes[1] ?? null;        // 01 | 02 | 03 ...
j.acao_resposta = partes.slice(2).join("_") || null;

// ======================================================
// FLAGS AUXILIARES
// ======================================================

j.respondeu_botao =
  j.tipo_resposta === "BOTAO";

j.respondeu_lista =
  j.tipo_resposta === "LISTA";

// ======================================================
// DEBUG
// ======================================================

j.debug_resposta = {
  tipo: j.tipo_resposta,
  fluxo: j.numero_fluxo,
  acao: j.acao_resposta,
  resposta_id: j.resposta_id,
  resposta_titulo: j.resposta_titulo
};

return item;

const item = $input.item;
const j = item.json;

// ======================================================
// ROUTER NEGOCIA
// Entrada esperada do nó anterior:
// Normalizar Resposta WhatsApp
//
// j.resposta_normalizada = BOTAO_01_VER_PENDENCIAS
// j.tipo_resposta        = BOTAO | LISTA
// j.numero_fluxo         = 01 | 02 | 03...
// j.acao_resposta        = VER_PENDENCIAS | NAO_INTERESSE...
// j.flow                 = estado atual da conversa
// ======================================================

const resposta = (j.resposta_normalizada ?? "").trim().toUpperCase();
const acao = (j.acao_resposta ?? "").trim().toUpperCase();
const flowAtual = (j.flow ?? "").trim().toUpperCase();

j.router = {
  origem: resposta,
  flow_anterior: flowAtual,
  proximo_flow: null,
  rota: null,
  motivo: null,
};

function route({ flow, rota, motivo, step, maturidade }) {
  j.router.proximo_flow = flow;
  j.router.rota = rota ?? flow;
  j.router.motivo = motivo;

  j.rota = rota ?? flow;
  j.flow = flow;

  if (step !== undefined) j.step = step;
  if (maturidade !== undefined) j.maturidade = maturidade;

  return item;
}

// ======================================================
// BOTAO 01 - CAMPANHA INICIAL
// ======================================================

if (resposta === "BOTAO_01_VER_PENDENCIAS") {
  return route({
    flow: "AUTENTICAR_CONSUMIDOR",
    motivo: "Consumidor deseja consultar pendências",
    step: 1,
  });
}

if (resposta === "BOTAO_01_NAO_INTERESSE") {
  return route({
    flow: "NAO_INTERESSE_MOTIVO",
    motivo: "Consumidor não deseja consultar pendências",
    step: 1,
    maturidade: 1,
  });
}

// ======================================================
// LISTA 01 - MOTIVO DO NÃO INTERESSE
// ======================================================

if (resposta === "LISTA_01_SEM_CONDICOES_FINANCEIRAS") {
  j.motivoinadimplencia = "SEM_CONDICOES_FINANCEIRAS";
  j.situacaoatual = "";
  j.objecao = "SEM_CONDICOES_FINANCEIRAS";

  return route({
    flow: "SEM_CONDICOES_FINANCEIRAS",
    rota: "SEM_CONDICOES_FINANCEIRAS",
    motivo: "Cliente informou que não possui condições financeiras no momento",
    step: 1,
    maturidade: 2,
  });
}

if (resposta === "LISTA_01_RESOLVER_FUTURAMENTE") {
  return route({
    flow: "PREVISAO_RETORNO",
    motivo: "Cliente pretende resolver futuramente",
    step: 1,
    maturidade: 2,
  });
}

if (resposta === "LISTA_01_DUVIDAS_COBRANCA") {
  return route({
    flow: "DUVIDA_COBRANCA",
    motivo: "Cliente possui dúvidas sobre cobrança",
    step: 1,
    maturidade: 3,
  });
}

if (resposta === "LISTA_01_NAO_RESPONSAVEL") {
  return route({
    flow: "NAO_RESPONSAVEL_LIGACAO",
    motivo: "Cliente informou não ser responsável pela ligação",
    step: 1,
    maturidade: 1,
  });
}

if (resposta === "LISTA_01_OUTRO_MOTIVO") {
  return route({
    flow: "OUTRO_MOTIVO_TEXTO_LIVRE",
    motivo: "Cliente deseja informar outro motivo",
    step: 1,
  });
}

// ======================================================
// LISTA 02 - PREVISÃO DE REGULARIZAÇÃO FUTURA
// ======================================================

if (resposta === "LISTA_02_30_DIAS") {
  j.previsaoregularizacao = "ATE_30_DIAS";
  j.previsaoregularizacaodias = 30;
  j.previsaoregularizacaodescricao = "Nos próximos 30 dias";

  j.proximaabordagem_dias = 30;
  j.riscoinadimplencia = "MEDIO";
  j.prioridaderecontato = "ALTA";
  j.intencaopagamento = "CURTO_PRAZO";
  j.objecao = "RESOLVER_FUTURAMENTE";

  j.ultimaacao = resposta;
  j.ultimaresposta = "Cliente informou previsão de regularização em até 30 dias";

  return route({
    flow: "ENCERRAR_COM_RECONTATO",
    rota: "ENCERRAR_COM_RECONTATO",
    motivo: "Cliente pretende regularizar nos próximos 30 dias",
    step: 2,
    maturidade: 4,
  });
}

if (resposta === "LISTA_02_30_90_DIAS") {
  j.previsaoregularizacao = "ENTRE_30_90_DIAS";
  j.previsaoregularizacaodias = 60;
  j.previsaoregularizacaodescricao = "Entre 30 e 90 dias";

  j.proximaabordagem_dias = 60;
  j.riscoinadimplencia = "ALTO";
  j.prioridaderecontato = "MEDIA";
  j.intencaopagamento = "MEDIO_PRAZO";
  j.objecao = "RESOLVER_FUTURAMENTE";

  j.ultimaacao = resposta;
  j.ultimaresposta = "Cliente informou previsão de regularização entre 30 e 90 dias";

  return route({
    flow: "ENCERRAR_COM_RECONTATO",
    rota: "ENCERRAR_COM_RECONTATO",
    motivo: "Cliente pretende regularizar entre 30 e 90 dias",
    step: 2,
    maturidade: 3,
  });
}

if (resposta === "LISTA_02_ACIMA_90_DIAS") {
  j.previsaoregularizacao = "ACIMA_90_DIAS";
  j.previsaoregularizacaodias = 90;
  j.previsaoregularizacaodescricao = "Acima de 90 dias";

  j.proximaabordagem_dias = 90;
  j.riscoinadimplencia = "MUITO_ALTO";
  j.prioridaderecontato = "BAIXA";
  j.intencaopagamento = "LONGO_PRAZO";
  j.objecao = "RESOLVER_FUTURAMENTE_LONGO_PRAZO";

  j.ultimaacao = resposta;
  j.ultimaresposta = "Cliente informou previsão de regularização acima de 90 dias";

  return route({
    flow: "ENCERRAR_COM_ALERTA",
    rota: "ENCERRAR_COM_ALERTA",
    motivo: "Cliente pretende regularizar somente após 90 dias",
    step: 2,
    maturidade: 2,
  });
}

if (resposta === "LISTA_02_AINDA_NAO_SEI") {
  j.previsaoregularizacao = "SEM_PREVISAO";
  j.previsaoregularizacaodias = null;
  j.previsaoregularizacaodescricao = "Sem previsão de regularização";

  j.proximaabordagem_dias = null;
  j.riscoinadimplencia = "CRITICO";
  j.prioridaderecontato = "BAIXA";
  j.intencaopagamento = "SEM_PREVISAO";
  j.objecao = "SEM_PREVISAO_REGULARIZACAO";

  j.ultimaacao = resposta;
  j.ultimaresposta = "Cliente informou não ter previsão de regularização";

  return route({
    flow: "ENCERRAR_COM_ALERTA",
    rota: "ENCERRAR_COM_ALERTA",
    motivo: "Cliente não possui previsão de regularização",
    step: 2,
    maturidade: 1,
  });
}

// ======================================================
// LISTA 03 - DÚVIDAS SOBRE COBRANÇA
// Todas as opções abaixo usam a rota genérica CONSULTAR_PENDENCIAS
// ======================================================

if (resposta === "LISTA_03_VALOR_DIVIDA") {
  j.tipo_duvida = "VALOR_DIVIDA";
  j.tipo_duvida_descricao = "Valor da dívida";

  j.ultimaacao = resposta;
  j.ultimaresposta = "Cliente possui dúvida sobre o valor da dívida";

  return route({
    flow: "CONSULTAR_PENDENCIAS",
    rota: "CONSULTAR_PENDENCIAS",
    motivo: "Cliente deseja consultar o detalhamento dos débitos por dúvida sobre valor da dívida",
    step: 2,
    maturidade: Math.max(j.maturidade ?? 1, 3),
  });
}

if (resposta === "LISTA_03_ORIGEM_COBRANCA") {
  j.tipo_duvida = "ORIGEM_COBRANCA";
  j.tipo_duvida_descricao = "Origem da cobrança";

  j.ultimaacao = resposta;
  j.ultimaresposta = "Cliente possui dúvida sobre a origem da cobrança";

  return route({
    flow: "CONSULTAR_PENDENCIAS",
    rota: "CONSULTAR_PENDENCIAS",
    motivo: "Cliente deseja consultar o detalhamento dos débitos por dúvida sobre origem da cobrança",
    step: 2,
    maturidade: Math.max(j.maturidade ?? 1, 3),
  });
}

if (resposta === "LISTA_03_REFERENCIAS_ABERTO") {
  j.tipo_duvida = "REFERENCIAS_ABERTO";
  j.tipo_duvida_descricao = "Faturas em aberto";

  j.ultimaacao = resposta;
  j.ultimaresposta = "Cliente possui dúvida sobre as faturas em aberto";

  return route({
    flow: "CONSULTAR_PENDENCIAS",
    rota: "CONSULTAR_PENDENCIAS",
    motivo: "Cliente deseja consultar o detalhamento das faturas em aberto",
    step: 2,
    maturidade: Math.max(j.maturidade ?? 1, 3),
  });
}

if (resposta === "LISTA_03_OUTRO_ASSUNTO") {
  j.tipo_duvida = "OUTRO_ASSUNTO";
  j.tipo_duvida_descricao = "Outro assunto";

  j.ultimaacao = resposta;
  j.ultimaresposta = "Cliente deseja informar outro assunto";

  return route({
    flow: "DUVIDA_COBRANCA",
    rota: "OUTRO_MOTIVO_TEXTO_LIVRE",
    motivo: "Cliente deseja informar outro assunto relacionado à cobrança",
    step: 2,
    maturidade: Math.max(j.maturidade ?? 1, 3),
  });
}

// ======================================================
// BOTAO 02 - DÚVIDA ESCLARECIDA
// ======================================================

if (resposta === "BOTAO_02_SIM") {
  return route({
    flow: "CONSULTAR_PENDENCIAS",
    motivo: "Cliente informou que a dúvida foi esclarecida",
  });
}

if (resposta === "BOTAO_02_NAO") {
  return route({
    flow: "ANALISE_HUMANA_DUVIDA",
    motivo: "Cliente ainda possui dúvidas",
  });
}

// ======================================================
// LISTA 04 - NÃO RESPONSÁVEL
// ======================================================

if (resposta === "LISTA_04_NUNCA_FUI_RESPONSAVEL") {
  j.tipo_problema_cadastral = "NUNCA_FUI_RESPONSAVEL";

  return route({
    flow: "NAO_RESPONSAVEL_LIGACAO",
    rota: "CADASTRO_NUNCA_RESPONSAVEL",
    motivo: "Cliente informou que nunca foi responsável por esta ligação",
    maturidade: 1,
  });
}

if (resposta === "LISTA_04_MUDEI_DO_IMOVEL") {
  j.tipo_problema_cadastral = "MUDEI_DO_IMOVEL";

  return route({
    flow: "NAO_RESPONSAVEL_LIGACAO",
    rota: "CADASTRO_MUDOU_DO_IMOVEL",
    motivo: "Cliente informou que mudou do imóvel",
    maturidade: 1,
  });
}

if (resposta === "LISTA_04_TRANSFERENCIA_NAO_REALIZADA") {
  j.tipo_problema_cadastral = "TRANSFERENCIA_NAO_REALIZADA";

  return route({
    flow: "NAO_RESPONSAVEL_LIGACAO",
    rota: "CADASTRO_TRANSFERENCIA_PENDENTE",
    motivo: "Cliente informou que a transferência de titularidade não foi realizada",
    maturidade: 1,
  });
}

// ======================================================
// BOTAO 03 - APÓS CONSULTAR PENDÊNCIAS
// ======================================================

if (resposta === "BOTAO_03_QUERO_RESOLVER") {
  return route({
    flow: "DIAGNOSTICO_MOTIVO_INADIMPLENCIA",
    rota: "DIAGNOSTICO_MOTIVO_INADIMPLENCIA",
    motivo: "Cliente deseja resolver",
    step: 1,
    maturidade: 3,
  });
}

if (resposta === "BOTAO_03_NAO_INTERESSE") {
  return route({
    flow: "NAO_INTERESSE_MOTIVO",
    rota: "NAO_INTERESSE_MOTIVO",
    motivo: "Cliente não deseja resolver após consultar pendências",
    step: 1,
    maturidade: 1,
  });
}

// ======================================================
// LISTA 05 - MOTIVO DA INADIMPLÊNCIA
// ======================================================

// ======================================================
// LISTA 05 - MOTIVO DA INADIMPLÊNCIA
// ======================================================

if (resposta.startsWith("LISTA_05_")) {
  const motivosInadimplencia = {
    LISTA_05_DIFICULDADES_FINANCEIRAS: {
      codigo: "DIFICULDADES_FINANCEIRAS",
      descricao: "Dificuldades financeiras",
      categoria: "FINANCEIRO",
      maturidade: 3,
    },
    LISTA_05_DESEMPREGO_REDUCAO_RENDA: {
      codigo: "DESEMPREGO_REDUCAO_RENDA",
      descricao: "Desemprego ou redução de renda",
      categoria: "RENDA",
      maturidade: 3,
    },
    LISTA_05_PROBLEMAS_SAUDE: {
      codigo: "PROBLEMAS_SAUDE",
      descricao: "Problemas de saúde",
      categoria: "SAUDE",
      maturidade: 3,
    },
    LISTA_05_ESQUECIMENTO_ORGANIZACAO: {
      codigo: "ESQUECIMENTO_ORGANIZACAO",
      descricao: "Esquecimento ou falta de organização",
      categoria: "ORGANIZACAO",
      maturidade: 4,
    },
    LISTA_05_OUTRO_MOTIVO: {
      codigo: "OUTRO_MOTIVO",
      descricao: "Outro motivo",
      categoria: "OUTROS",
      maturidade: 3,
    },
  };

  const motivoSelecionado = motivosInadimplencia[resposta];

  j.motivoinadimplencia = motivoSelecionado?.codigo ?? acao;
  j.motivoinadimplenciadescricao = motivoSelecionado?.descricao ?? acao;
  j.categoriainadimplencia = motivoSelecionado?.categoria ?? "NAO_CLASSIFICADO";

  j.ultimaacao = resposta;
  j.ultimaresposta = j.motivoinadimplenciadescricao;

  if (resposta === "LISTA_05_OUTRO_MOTIVO") {
    return route({
      flow: "AGUARDANDO_MOTIVO_INADIMPLENCIA_TEXTO_LIVRE",
      rota: "SOLICITAR_MOTIVO_INADIMPLENCIA_TEXTO_LIVRE",
      motivo: "Cliente informou outro motivo para inadimplência",
      step: 2,
      maturidade: 3,
    });
  }

  return route({
    flow: "DIAGNOSTICO_SITUACAO_ATUAL",
    rota: "DIAGNOSTICO_SITUACAO_ATUAL",
    motivo: `Motivo da inadimplência informado: ${j.motivoinadimplenciadescricao}`,
    step: 2,
    maturidade: Math.max(j.maturidade ?? 1, 3),
  });
}

// ======================================================
// LISTA 06 - SITUAÇÃO ATUAL
// ======================================================

if (resposta === "BOTAO_06_ESTAVEL") {
  j.situacaoatual = "ESTAVEL";

  return route({
    flow: "PERFIL_FINANCEIRO_ESTAVEL",
    rota: "PERFIL_FINANCEIRO_ESTAVEL",
    motivo: "Cliente informou que sua situação financeira está estável",
    step: 3,
    maturidade: 5,
  });
}

if (resposta === "BOTAO_06_MELHORANDO") {
  j.situacaoatual = "MELHORANDO";

  return route({
    flow: "PERFIL_FINANCEIRO_MELHORANDO",
    rota: "PERFIL_FINANCEIRO_MELHORANDO",
    motivo: "Cliente informou que sua situação financeira está melhorando",
    step: 3,
    maturidade: 4,
  });
}

if (resposta === "BOTAO_06_AINDA_COM_DIFICULDADES") {
  j.situacaoatual = "AINDA_COM_DIFICULDADES";

  return route({
    flow: "PERFIL_FINANCEIRO_DIFICULDADES",
    rota: "PERFIL_FINANCEIRO_DIFICULDADES",
    motivo: "Cliente informou que ainda está com dificuldades financeiras",
    step: 3,
    maturidade: 3,
  });
}

// ======================================================
// BOTAO 04 - PERFIL FINANCEIRO ESTÁVEL
// Opções após oferta à vista com desconto
// ======================================================

if (resposta === "BOTAO_04_QUITAR_COM_DESCONTO") {
  j.preferenciapagamento = "QUITACAO";
  j.tipoProposta = "QUITACAO_A_VISTA";
  j.objecao = null;

  j.ultimaacao = resposta;
  j.ultimaresposta = "Cliente escolheu quitação à vista com desconto";

  return route({
    flow: "SOLICITAR_PROPOSTA_QUITACAO",
    rota: "SOLICITAR_PROPOSTA_QUITACAO",
    motivo: "Cliente escolheu quitação à vista com desconto",
    step: 4,
    maturidade: 5,
  });
}

if (resposta === "BOTAO_04_VER_OUTRAS_OPCOES") {
  j.preferenciapagamento = "PARCELAMENTO";
  j.tipoProposta = "PARCELAMENTO";
  j.objecao = "NAO_OPTOU_QUITACAO_A_VISTA";

  j.ultimaacao = resposta;
  j.ultimaresposta = "Cliente deseja ver opções de parcelamento";

  return route({
    flow: "OPCOES_PARCELAMENTO",
    rota: "OPCOES_PARCELAMENTO",
    motivo: "Cliente não optou pela quitação à vista e deseja ver opções de parcelamento",
    step: 4,
    maturidade: 4,
  });
}

// ======================================================
// LISTA 07 - CAPACIDADE DE PAGAMENTO
// ======================================================

if (resposta.startsWith("LISTA_07_")) {
  const mapaValores = {
    LISTA_07_ATE_50: {
      valor: 50,
      faixa: "ATE_50",
      descricao: "Até R$ 50,00",
    },
    LISTA_07_ATE_100: {
      valor: 100,
      faixa: "ATE_100",
      descricao: "Até R$ 100,00",
    },
    LISTA_07_ATE_200: {
      valor: 200,
      faixa: "ATE_200",
      descricao: "Até R$ 200,00",
    },
