function numero(valor) {
  if (valor === undefined || valor === null || valor === "") return 0;

  if (typeof valor === "string") {
    valor = valor.replace(/\./g, "").replace(",", ".");
  }

  const n = Number(valor);
  return Number.isFinite(n) ? n : 0;
}

function moeda(valor) {
  return numero(valor).toLocaleString("pt-BR", {
    style: "currency",
    currency: "BRL",
  });
}

function dataReferencia(ref) {
  if (!ref || typeof ref !== "string") return new Date("9999-12-31");

  const [mes, ano] = ref.split("/");
  return new Date(`${ano}-${mes}-01`);
}

// A nova API está retornando 1 débito por item
const retorno = items.flatMap(item => {
  const e = item.json;

  if (Array.isArray(e)) return e;
  if (Array.isArray(e.data)) return e.data;
  if (Array.isArray(e.debitos)) return e.debitos;
  if (Array.isArray(e.faturas)) return e.faturas;
  if (Array.isArray(e.body)) return e.body;
  if (Array.isArray(e.retorno)) return e.retorno;

  return [e];
});

const debitos = retorno
  .map(d => {
    const valorOriginal = numero(d.valorOriginal);
    const valorAtualizado = numero(d.valorAtualizado);
    const juros = numero(d.juros);
    const multa = numero(d.multa);
    const correcao = numero(d.correcaoMonetaria);

    return {
      debitoDetalheId: d.debitoDetalheId ?? null,
      referencia: d.referencia ?? "",
      statusDescricao: d.statusDescricao ?? "",
      valorOriginal,
      valorAtualizado,
      juros,
      multa,
      correcao,
      codigoBarras: d.codigoBarras ?? null,
      linhaDigitavel: d.linhaDigitavel ?? null,
    };
  })
  .sort((a, b) => dataReferencia(a.referencia) - dataReferencia(b.referencia));

const totalFaturas = debitos.reduce((acc, d) => acc + d.valorOriginal, 0);
const totalJuros = debitos.reduce((acc, d) => acc + d.juros, 0);
const totalMulta = debitos.reduce((acc, d) => acc + d.multa, 0);
const totalCorrecao = debitos.reduce((acc, d) => acc + d.correcao, 0);
const totalAtualizado = debitos.reduce((acc, d) => acc + d.valorAtualizado, 0);

const linhas = debitos.map(d => {
  return `${d.referencia} .......... ${moeda(d.valorAtualizado)}`;
});

j.reply =
  `*Apresentamos abaixo as pendências atualmente identificadas para esta ligação.*\n\n` +
  `*Total atualizado: ${moeda(totalAtualizado)}*\n\n` +
  `*Referência       Valor atualizado*\n` +
  `${linhas.join("\n")}\n\n` +
  `*Resumo dos valores*\n\n` +
  `Faturas: ${moeda(totalFaturas)}\n` +
  `Juros: ${moeda(totalJuros)}\n` +
  `Multa: ${moeda(totalMulta)}\n` +
  `Correção: ${moeda(totalCorrecao)}\n\n` +
  `*Valor total atualizado: ${moeda(totalAtualizado)}*\n\n` +
  `Regularizar sua situação agora pode ajudar a evitar o aumento dos débitos e possíveis restrições previstas para a prestação do serviço.`;

j.debitos = debitos;
j.totalFaturas = totalFaturas;
j.totalConsumo = totalFaturas;
j.totalJuros = totalJuros;
j.totalMulta = totalMulta;
j.totalCorrecao = totalCorrecao;
j.totalDebitos = totalAtualizado;
j.totalAtualizado = totalAtualizado;
j.quantidadeDebitos = debitos.length;

return [
  {
    json: j,
  },
];

