function numero(valor) {
  if (valor === undefined || valor === null || valor === "") return 0;

  if (typeof valor === "number") return valor;

  if (typeof valor === "string") {
    valor = valor
      .replace("R$", "")
      .replace(/\s/g, "")
      .replace(/\./g, "")
      .replace(",", ".");
  }

  const n = Number(valor);
  return Number.isFinite(n) ? n : 0;
}

function moeda(valor) {
  return numero(valor).toLocaleString("pt-BR", {
    style: "currency",
    currency: "BRL",
  });
}

const respostaId = j.resposta_normalizada ?? j.resposta_id ?? "";
const respostaTitulo = j.resposta_titulo ?? "";
const respostaDescricao = j.resposta_descricao ?? "";

// Exemplo: LISTA_08_PARC_09
const matchParcelasId = respostaId.match(/PARC_(\d+)/);
const parcelasPeloId = matchParcelasId ? Number(matchParcelasId[1]) : null;

// Exemplo: 9x R$ 165,42
const matchTitulo = respostaTitulo.match(/(\d+)x\s*R\$\s*([\d.,]+)/i);
const parcelasPeloTitulo = matchTitulo ? Number(matchTitulo[1]) : null;
const valorParcelaPeloTitulo = matchTitulo ? numero(matchTitulo[2]) : 0;

// Exemplo: Total R$ 1.488,77
const matchTotal = respostaDescricao.match(/R\$\s*([\d.,]+)/i);
const valorTotalPelaDescricao = matchTotal ? numero(matchTotal[1]) : 0;

const proposta = (j.opcoesParcelamento || []).find(
  p => p.id === respostaId
);

const parcelas =
  proposta?.parcelas ??
  j.parcelasEscolhidas ??
  parcelasPeloId ??
  parcelasPeloTitulo ??
  null;

const valorParcela =
  proposta?.valorParcela ??
  j.valorParcelaEscolhida ??
  valorParcelaPeloTitulo ??
  0;

const valorTotal =
  proposta?.totalNegociado ??
  j.valorTotalNegociado ??
  valorTotalPelaDescricao ??
  j.totalAtualizado ??
  j.totalDebitos ??
  0;

const desconto =
  proposta?.descontoEncargos ??
  j.descontoEncargosEscolhido ??
  j.percentualDescontoEscolhido ??
  0;

j.proposta_escolhida = proposta?.id ?? respostaId;
